CREATE TYPE "DeveloperApplicationEnvironment" AS ENUM ('DEVELOPMENT','SANDBOX','PRODUCTION');
CREATE TYPE "DeveloperApplicationStatus" AS ENUM ('ACTIVE','SUSPENDED');
CREATE TYPE "DeveloperCredentialStatus" AS ENUM ('ACTIVE','REVOKED','EXPIRED');
CREATE TYPE "DeveloperAccessGrantStatus" AS ENUM ('ACTIVE','REVOKED');
CREATE TYPE "DeveloperRateLimitPeriod" AS ENUM ('MINUTE','HOUR','DAY','MONTH');
CREATE TYPE "DeveloperRateLimitDecision" AS ENUM ('ALLOWED','DENIED');
CREATE TABLE "DeveloperApiScope" ("id" TEXT PRIMARY KEY,"key" TEXT NOT NULL UNIQUE,"description" TEXT NOT NULL,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "DeveloperRateLimitPolicy" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"limit" INTEGER NOT NULL,"burstLimit" INTEGER NOT NULL,"period" "DeveloperRateLimitPeriod" NOT NULL,"environment" "DeveloperApplicationEnvironment" NOT NULL DEFAULT 'PRODUCTION',"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "DeveloperRateLimitPolicy_organizationId_name_environment_key" ON "DeveloperRateLimitPolicy"("organizationId","name","environment");
CREATE TABLE "DeveloperApplication" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"ownerUserId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"environment" "DeveloperApplicationEnvironment" NOT NULL DEFAULT 'DEVELOPMENT',"status" "DeveloperApplicationStatus" NOT NULL DEFAULT 'ACTIVE',"redirectUris" TEXT[] NOT NULL,"requestedScopes" TEXT[] NOT NULL,"rateLimitPolicyId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DeveloperApplication_rateLimitPolicyId_fkey" FOREIGN KEY ("rateLimitPolicyId") REFERENCES "DeveloperRateLimitPolicy"("id") ON DELETE SET NULL);
CREATE TABLE "DeveloperCredential" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"applicationId" TEXT NOT NULL,"name" TEXT NOT NULL,"prefix" TEXT NOT NULL,"secretHash" TEXT NOT NULL UNIQUE,"scopes" TEXT[] NOT NULL,"status" "DeveloperCredentialStatus" NOT NULL DEFAULT 'ACTIVE',"lastUsedAt" TIMESTAMP(3),"expiresAt" TIMESTAMP(3),"revokedAt" TIMESTAMP(3),"replacedById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DeveloperCredential_applicationId_fkey" FOREIGN KEY ("applicationId") REFERENCES "DeveloperApplication"("id") ON DELETE CASCADE);
CREATE TABLE "DeveloperAccessGrant" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"applicationId" TEXT NOT NULL,"credentialId" TEXT,"scope" TEXT NOT NULL,"resourceType" TEXT,"resourceId" TEXT,"status" "DeveloperAccessGrantStatus" NOT NULL DEFAULT 'ACTIVE',"expiresAt" TIMESTAMP(3),"revokedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DeveloperAccessGrant_applicationId_fkey" FOREIGN KEY ("applicationId") REFERENCES "DeveloperApplication"("id") ON DELETE CASCADE,CONSTRAINT "DeveloperAccessGrant_credentialId_fkey" FOREIGN KEY ("credentialId") REFERENCES "DeveloperCredential"("id") ON DELETE CASCADE);
CREATE TABLE "DeveloperApiRequestLog" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"applicationId" TEXT,"credentialId" TEXT,"endpoint" TEXT NOT NULL,"method" TEXT NOT NULL,"statusCode" INTEGER NOT NULL,"durationMs" INTEGER NOT NULL,"correlationId" TEXT NOT NULL,"rateLimitDecision" "DeveloperRateLimitDecision" NOT NULL DEFAULT 'ALLOWED',"idempotencyKey" TEXT,"occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "DeveloperApiRequestLog_applicationId_fkey" FOREIGN KEY ("applicationId") REFERENCES "DeveloperApplication"("id") ON DELETE SET NULL,CONSTRAINT "DeveloperApiRequestLog_credentialId_fkey" FOREIGN KEY ("credentialId") REFERENCES "DeveloperCredential"("id") ON DELETE SET NULL);
CREATE INDEX "DeveloperApplication_organizationId_status_environment_idx" ON "DeveloperApplication"("organizationId","status","environment");
CREATE INDEX "DeveloperCredential_organizationId_applicationId_status_idx" ON "DeveloperCredential"("organizationId","applicationId","status");
CREATE INDEX "DeveloperAccessGrant_organizationId_applicationId_status_idx" ON "DeveloperAccessGrant"("organizationId","applicationId","status");
CREATE INDEX "DeveloperApiRequestLog_organizationId_occurredAt_idx" ON "DeveloperApiRequestLog"("organizationId","occurredAt");
CREATE INDEX "DeveloperApiRequestLog_correlationId_idx" ON "DeveloperApiRequestLog"("correlationId");
